-{"id":"jeffreysprompts.com-hrjj","title":"Implement dark mode with system preference","description":"## Origin
Mirror from jeffreysprompts_premium jeffreysprompts_premium-2ja. Keep both repos in sync.

## Task
Implement dark mode with system preference detection and user override.

## Why This Matters
From README: "We optimize for an elite UX across desktop and mobile."
Dark mode is essential for:
- User comfort in low-light environments
- Modern, polished appearance
- Accessibility (some users need high contrast)

## Implementation

### 1. Theme Provider
```typescript
// src/components/providers/theme-provider.tsx
"use client";

import { createContext, useContext, useEffect, useState } from "react";

type Theme = "light" | "dark" | "system";

interface ThemeContextType {
  theme: Theme;
  setTheme: (theme: Theme) => void;
  resolvedTheme: "light" | "dark";
}

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<Theme>("system");
  const [resolvedTheme, setResolvedTheme] = useState<"light" | "dark">("light");

  useEffect(() => {
    const stored = localStorage.getItem("theme") as Theme;
    if (stored) setTheme(stored);
  }, []);

  useEffect(() => {
    const mediaQuery = window.matchMedia("(prefers-color-scheme: dark)");
    const updateResolved = () => {
      const resolved = theme === "system" 
        ? (mediaQuery.matches ? "dark" : "light")
        : theme;
      setResolvedTheme(resolved);
      document.documentElement.classList.toggle("dark", resolved === "dark");
    };

    updateResolved();
    mediaQuery.addEventListener("change", updateResolved);
    return () => mediaQuery.removeEventListener("change", updateResolved);
  }, [theme]);

  return (
    <ThemeContext.Provider value={{ theme, setTheme, resolvedTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}
```

### 2. Theme Toggle Component
```typescript
// src/components/ui/theme-toggle.tsx
export function ThemeToggle() {
  const { theme, setTheme } = useTheme();
  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button variant="ghost" size="icon">
          <Sun className="h-5 w-5 dark:hidden" />
          <Moon className="h-5 w-5 hidden dark:block" />
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent>
        <DropdownMenuItem onClick={() => setTheme("light")}>Light</DropdownMenuItem>
        <DropdownMenuItem onClick={() => setTheme("dark")}>Dark</DropdownMenuItem>
        <DropdownMenuItem onClick={() => setTheme("system")}>System</DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
```

### 3. CSS Variables (in globals.css)
Already implemented in scaffold:
```css
:root {
  --background: #ffffff;
  --foreground: #0a0a0a;
  /* ... */
}

.dark {
  --background: #0a0a0a;
  --foreground: #ededed;
  /* ... */
}
```

### 4. Prevent Flash of Wrong Theme
```typescript
// In layout.tsx <head>
<script dangerouslySetInnerHTML={{
  __html: `
    (function() {
      const stored = localStorage.getItem('theme');
      const prefersDark = window.matchMedia('(prefers-color-scheme: dark)').matches;
      const isDark = stored === 'dark' || (!stored && prefersDark);
      if (isDark) document.documentElement.classList.add('dark');
    })();
  `
}} />
```

### 5. Persist User Preference
- Store in localStorage for immediate use
- Sync to user_profiles.theme_preference for cross-device
- Apply on initial load before hydration

## Components to Update
- All UI components should use CSS variables
- Images should have dark mode variants if needed
- Code syntax highlighting theme should switch
- Charts/graphs should use appropriate colors

## Files to Create
- `src/components/providers/theme-provider.tsx`
- `src/components/ui/theme-toggle.tsx`
- `src/hooks/use-theme.ts`

## Success Criteria
- Theme toggles between light/dark/system
- No flash of wrong theme on page load
- Preference persists across sessions
- All components look good in both themes
- Follows system preference when set to "system"
